formatting.json_schema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "required": ["summary", "skills"],
  "properties": {
    "summary": {
      "type": "string",
      "description": "High-level Markdown summary of the memory records, organized by area/topic"
    },
    "skills": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["id", "title", "instruction", "tags"],
        "properties": {
          "id": {
            "type": "string",
            "pattern": "^sk_[0-9]+$",
            "description": "Temporary skill id, e.g. sk_1. The system will remap to sk_0001"
          },
          "title": {
            "type": "string",
            "description": "Short title of the skill"
          },
          "instruction": {
            "type": "string",
            "description": "Concrete instruction or know-how derived from memory"
          },
          "tags": {
            "type": "array",
            "items": {"type": "string"},
            "description": "Related tags for discoverability"
          }
        }
      }
    }
  }
}

example.ai:
{
  "summary": "The records cover Dart error handling and Flutter state management best practices.",
  "skills": [
    {
      "id": "sk_1",
      "title": "Handle async errors",
      "instruction": "Use try/catch or Result wrappers to handle async errors in Dart.",
      "tags": ["dart", "errors"]
    },
    {
      "id": "sk_2",
      "title": "Choose Flutter state management",
      "instruction": "Prefer Riverpod for global state management in Flutter apps.",
      "tags": ["flutter", "riverpod", "state-management"]
    }
  ]
}
